   197→#if defined(NCCL_HAS_COMM_SPLIT)
   198→std::shared_ptr<NCCLComm> NCCLComm::split(
   199→    NCCLComm* source,
   200→    int color_id,
   201→    int rank,
   202→    ncclConfig_t& config) {
   203→  TORCH_CHECK(
   204→      color_id >= NCCL_SPLIT_NOCOLOR,
   205→      "Color must be a non-negative value or NCCL_SPLIT_NOCOLOR (-1)"
   206→      ", but got ",
   207→      color_id);
   208→  LOG(INFO) << "Rank " << source->rank_ << ": split from parent comm "
   209→            << source->repr() << " with color_id " << color_id << " and rank "
   210→            << rank;
   211→  at::cuda::OptionalCUDAGuard gpuGuard(source->deviceIndex_);
   212→  auto comm = std::make_shared<NCCLComm>();
   213→  // This call will block until the source communicator is initialized
   214→  auto sourceComm = source->getNcclComm();
   215→#ifndef NCCL_HAS_COMM_NONBLOCKING
   216→  C10D_NCCL_CHECK(
   217→      ncclCommSplit(sourceComm, color_id, rank, &(comm->ncclComm_), &config),
   218→      std::nullopt);
   219→#else
   220→  // After calling ncclCommSplit in non-blocking mode, we should wait for the
   221→  // source communicator to be out of ncclInProgress state.
   222→  // Reason 1:
   223→  //   it's unsafe to call new operations on the parent comm while it's in
   224→  //   ncclInProgress state.
   225→  // Reason 2:
   226→  //   as of NCCL 2.23, the ptr value of child comm will not be filled until the
   227→  //   state of parent comm is ncclSuccess. This may change in the future. See:
   228→  //   https://github.com/NVIDIA/nccl/issues/1472
   229→  C10D_NCCL_CHECK_TIMEOUT_SLEEP(
   230→      ncclCommSplit(sourceComm, color_id, rank, &(comm->ncclComm_), &config),
   231→      sourceComm, // wait on parent comm
   232→      std::nullopt);
   233→  if (color_id >= 0) {
   234→    // Waiting for parent comm above still does not seem to guarantee the child
   235→    // comm ptr is valid. Therefore we add a manual wait here for safety.
   236→    // TODO: remove this wait after NCCL fix the semantics.
   237→    auto startTime = std::chrono::steady_clock::now();
   238→    auto timeout = nccl_nonblocking_timeout();
   239→    while (!comm->ncclComm_) {
   240→      C10D_CHECK_TIMEOUT(startTime, timeout);
   241→      C10D_SCHED_SLEEP();
   242→    }
   243→  }
   244→  // comm->ncclComm_ should have valid ptr by now, but not necessarily
   245→  // initialized. Rely on getNcclComm() to wait for its initialization.
   246→#endif
   247→  ++source->ncclCommSplitCounter_;
   248→  comm->rank_ = rank;
   249→  // Child comm should be on the same device as parent comm
   250→  comm->deviceIndex_ = source->deviceIndex_;
   251→  comm->nonBlocking_ = config.blocking == 0;
   252→  comm->setUniqueHash(
   253→      source->getUniqueHash() + ":" +
   254→      std::to_string(source->ncclCommSplitCounter_));
   255→  LOG(INFO) << "Rank " << source->rank_ << ": created child comm "
   256→            << comm->repr() << " with color_id " << color_id;
   257→  return comm;
   258→}
   259→#endif
