   320→void NCCLComm::finalize() {
   321→  LockType lock(mutex_);
   322→  if (aborted_) {
   323→    LOG(INFO) << "Rank " << rank_
   324→              << ": NCCL communicator already Invalidated. Skip finalize.";
   325→    return;
   326→  }
   327→  at::cuda::OptionalCUDAGuard gpuGuard(deviceIndex_);
   328→  auto comm = getNcclComm();
   329→  C10D_NCCL_CHECK_NONBLOCKING(ncclCommFinalize(comm), std::nullopt);
   330→}
