   424→ncclResult_t NCCLComm::registerSegment(
   425→    void* ptr,
   426→    size_t size,
   427→    bool errorOnRereg, /*=true*/
   428→    bool window /*=false*/) {
   429→  LockType lock(mutex_);
   430→#ifdef NCCL_HAS_COMM_REGISTER
   431→  // We register only segments from cache allocator
   432→  // which are guaranteed to be with disjoint addr ranges. Thus, a ptr always
   433→  // maps to a unique handle and should not be registered before the current
   434→  // ptr is deregistered and freed.
   435→  if (registeredSegmentHandles_.count(ptr) > 0) {
   436→    TORCH_CHECK(
   437→        !errorOnRereg,
   438→        "Segment with ptr ",
   439→        ptr,
   440→        " has already been registered on ncclComm_ ",
   441→        ncclComm_);
   442→    // Skip below
   443→    return ncclSuccess;
   444→  }
   445→
   446→  void* handle = nullptr;
   447→  // Use getNcclComm to make sure comm is ready before calling nccl APIs
   448→  auto comm = getNcclComm();
   449→#ifdef NCCL_HAS_COMM_WINDOW_REGISTER
   450→  if (window) {
   451→    C10D_NCCL_CHECK(
   452→        ncclCommWindowRegister(
   453→            comm, ptr, size, (ncclWindow_t*)&handle, NCCL_WIN_COLL_SYMMETRIC),
   454→        c10::str(
   455→            "Failed to window register segment with ptr ",
   456→            ptr,
   457→            ", size ",
   458→            size,
   459→            " on ncclComm_ ",
   460→            comm));
   461→  } else {
   462→    C10D_NCCL_CHECK(
   463→        ncclCommRegister(comm, ptr, size, &handle),
   464→        c10::str(
   465→            "Failed to register segment with ptr ",
   466→            ptr,
   467→            ", size ",
   468→            size,
   469→            " on ncclComm_ ",
   470→            comm));
   471→  }
   472→#else
   473→  C10D_NCCL_CHECK(
   474→      ncclCommRegister(comm, ptr, size, &handle),
   475→      c10::str(
   476→          "Failed to register segment with ptr ",
   477→          ptr,
   478→          ", size ",
   479→          size,
   480→          " on ncclComm_ ",
   481→          comm));
   482→#endif
   483→  registeredSegmentHandles_[ptr] = handle;
   484→  return ncclSuccess;
   485→#else
   486→  return ncclInvalidUsage;
   487→#endif
   488→}
   489→
   490→ncclResult_t NCCLComm::deregisterSegment(void* ptr, bool window /*false*/) {
   491→  LockType lock(mutex_);
   492→#ifdef NCCL_HAS_COMM_REGISTER
   493→  TORCH_CHECK(
   494→      registeredSegmentHandles_.count(ptr) == 1,
   495→      "Segment with ptr ",
   496→      ptr,
   497→      " is not registered on ncclComm_ ",
   498→      ncclComm_);
   499→
   500→  void* handle = registeredSegmentHandles_[ptr];
   501→  // Use getNcclComm to make sure comm is ready before calling nccl APIs
   502→  auto comm = getNcclComm();
   503→#ifdef NCCL_HAS_COMM_WINDOW_REGISTER
   504→  if (window) {
   505→    C10D_NCCL_CHECK(
   506→        ncclCommWindowDeregister(comm, (ncclWindow_t)handle),
   507→        c10::str(
   508→            "Failed to window deregister segment handle ",
   509→            handle,
   510→            ", with ptr ",
   511→            ptr,
   512→            " on ncclComm_ ",
   513→            comm));
   514→  } else {
   515→    C10D_NCCL_CHECK(
   516→        ncclCommDeregister(comm, handle),
   517→        c10::str(
   518→            "Failed to deregister segment handle ",
   519→            handle,
   520→            ", with ptr ",
   521→            ptr,
   522→            " on ncclComm_ ",
   523→            comm));
   524→  }
   525→#else
   526→  C10D_NCCL_CHECK(
   527→      ncclCommDeregister(comm, handle),
   528→      c10::str(
   529→          "Failed to deregister segment handle ",
   530→          handle,
   531→          ", with ptr ",
   532→          ptr,
   533→          " on ncclComm_ ",
   534→          comm));
   535→#endif
   536→  registeredSegmentHandles_.erase(ptr);
   537→  return ncclSuccess;
   538→#else
   539→  return ncclInvalidUsage;
   540→#endif
   541→}
