   559→std::string getNcclVersion() {
   560→  static std::string versionString = []() {
   561→    auto [ncclMajor, ncclMinor, ncclPatch] = getNcclVersionTuple();
   562→    std::string versionString;
   563→    if (ncclMajor == 0 && ncclMinor == 0 && ncclPatch == 0) {
   564→      versionString = "Unknown NCCL version";
   565→    } else {
   566→      versionString = std::to_string(ncclMajor) + "." +
   567→          std::to_string(ncclMinor) + "." + std::to_string(ncclPatch);
   568→#ifdef NCCL_SUFFIX
   569→      const auto ncclSuffix = std::string(NCCL_SUFFIX);
   570→      if (!ncclSuffix.empty()) {
   571→        versionString += "." + ncclSuffix;
   572→      }
   573→#endif
   574→    }
   575→    return versionString;
   576→  }();
   577→
   578→  return versionString;
   579→}
   580→
   581→std::tuple<int, int, int> getNcclVersionTuple() {
   582→  static std::tuple<int, int, int> versionTuple = []() {
   583→    int version = getNcclVersionNumber();
   584→    // can't compute the version if call did not return successfully or version
   585→    // code < 100 (corresponding to 0.1.0)
   586→    if (version < 100) {
   587→      return std::make_tuple(0, 0, 0);
   588→    }
