   634→// NCCL uses Non-negative int to represent in-group according to API
   635→// requirement. We take a list of ranks and generate a hash value based on the
   636→// list and ensure its range of 32-bit int.
   637→int genNcclSplitColor(const std::vector<int>& ranks) {
   638→  // Combine the hash values using a simple reducer (std::hash + fold)
   639→  std::size_t combined_hash = std::accumulate(
   640→      ranks.begin(),
   641→      ranks.end(),
   642→      std::size_t(0),
   643→      [](std::size_t acc, int rank) {
   644→        return acc ^
   645→            (std::hash<int>{}(rank) + 0x9e3779b9 + (acc << 6) + (acc >> 2));
   646→      });
   647→
   648→  // max positive value of int32_t
   649→  constexpr int32_t max_c_int = std::numeric_limits<int32_t>::max();
   650→  int color = static_cast<int>(
   651→      std::abs(static_cast<int64_t>(combined_hash)) % max_c_int);
   652→  return color;
   653→}
