   675→// Provides additional detail into NCCL error codes based on when these are
   676→// thrown in the NCCL codebase.
   677→std::string getNcclErrorDetailStr(
   678→    ncclResult_t error,
   679→    std::optional<std::string> processGroupFailureReason /* = std::nullopt */
   680→) {
   681→  // Prioritize failure reason provided by PG NCCL first, as it can abort
   682→  // communicators when it encounters collective timeouts, etc.
   683→  if (processGroupFailureReason != std::nullopt) {
   684→    return *processGroupFailureReason;
   685→  }
   686→  std::string interpret;
   687→  std::string err;
   688→#ifdef ENABLE_NCCL_GET_LAST_ERROR
   689→  auto ret = ncclGetLastError(nullptr);
   690→  if (ret) {
   691→    err = "\nLast error:\n" + std::string(ret);
   692→  } else {
   693→    err = "\nLast error: Unknown NCCL Error\n";
   694→  }
   695→#endif
   696→  switch (error) {
   697→    case ncclUnhandledCudaError:
   698→      interpret = "ncclUnhandledCudaError: Call to CUDA function failed.";
   699→      break;
   700→    case ncclSystemError:
   701→      interpret =
   702→          "ncclSystemError: System call (e.g. socket, malloc) or external library call failed or device error. ";
   703→#ifndef NCCL_REMOTE_ERROR
   704→      // Before ncclRemoteError was created, unexpected remote disconnect was
   705→      // categorized as ncclSystemError
   706→      interpret += "It can be also caused by unexpected exit of a remote peer.";
   707→#endif
   708→      break;
   709→    case ncclInternalError:
   710→      interpret = "ncclInternalError: Internal check failed.";
   711→      break;
   712→    case ncclInvalidArgument:
   713→      interpret = "ncclInvalidArgument: Invalid value for an argument.";
   714→      break;
   715→    case ncclInvalidUsage:
   716→      interpret =
   717→          "ncclInvalidUsage: This usually reflects invalid usage of NCCL library.";
   718→      break;
   719→#ifdef NCCL_REMOTE_ERROR
   720→    case ncclRemoteError:
   721→      interpret =
   722→          "ncclRemoteError: A call failed possibly due to a network error or a remote process exiting prematurely.";
   723→      break;
   724→#endif
   725→    default:
   726→      interpret = "Unknown NCCL error!";
   727→  }
   728→  return interpret + err;
   729→}
