    71→#ifdef ENABLE_NCCL_PREMUL_SUM_SUPPORT
    72→template <typename T, ncclDataType_t dataType>
    73→ncclRedOpRAII unpackPreMulSum(
    74→    const ReduceOp& reduceOp,
    75→    const ncclComm_t& comm) {
    76→  const auto* preMulSupplement =
    77→      reinterpret_cast<NCCLPreMulSumSupplement*>(reduceOp.supplement_.get());
    78→  ncclRedOp_t preMulSum{};
    79→  bool has_tensor = preMulSupplement->tensor_factor.defined();
    80→  auto residence = has_tensor ? ncclScalarDevice : ncclScalarHostImmediate;
    81→  const T* ptr_factor = has_tensor
    82→      ? preMulSupplement->tensor_factor.const_data_ptr<T>()
    83→      : nullptr;
    84→  T scalar_factor = T(preMulSupplement->double_factor);
    85→  ncclRedOpCreatePreMulSum(
    86→      &preMulSum,
    87→      // https://docs.nvidia.com/deeplearning/nccl/user-guide/docs/api/ops.html#ncclredopcreatepremulsum
    88→      // tells us that the scalar input is strictly a multiplier.
    89→      // NOLINTNEXTLINE(cppcoreguidelines-pro-type-const-cast)
    90→      /*scalar=*/has_tensor ? const_cast<T*>(ptr_factor) : &scalar_factor,
    91→      dataType,
    92→      residence,
    93→      comm);
    94→  return ncclRedOpRAII(preMulSum, comm);
    95→}
    96→#endif // ENABLE_NCCL_PREMUL_SUM_SUPPORT
