    98→ncclRedOpRAII getNcclReduceOp(
    99→    const ReduceOp& reduceOp,
   100→    at::Tensor& input,
   101→    const ncclDataType_t& dataType,
   102→    const ncclComm_t& comm) {
   103→  try {
   104→    if (input.scalar_type() == at::kBool) {
   105→      if (reduceOp == ReduceOp::SUM) {
   106→        // For bool tensors, map sum to max, which both represent a bitwise or.
   107→        // This is to prevent overflow issues with sum, since we use uint8 to
   108→        // represent a bool (see ncclDataType mapping).
   109→        return ncclMax;
   110→      }
   111→#ifdef NCCL_HAS_AVG
   112→      if (reduceOp == ReduceOp::AVG) {
   113→        C10_THROW_ERROR(
   114→            TypeError, "Cannot use ReduceOp.AVG with boolean inputs");
   115→      }
   116→#endif // NCCL_HAS_AVG
   117→    }
   118→    if (reduceOp == ReduceOp::PREMUL_SUM) {
   119→#ifdef ENABLE_NCCL_PREMUL_SUM_SUPPORT
   120→      switch (dataType) {
   121→        case ncclHalf:
   122→          return unpackPreMulSum<at::Half, ncclHalf>(reduceOp, comm);
   123→        case ncclFloat:
   124→          return unpackPreMulSum<float, ncclFloat>(reduceOp, comm);
   125→        case ncclBfloat16:
   126→          return unpackPreMulSum<float, ncclBfloat16>(reduceOp, comm);
   127→        case ncclDouble:
   128→          return unpackPreMulSum<double, ncclDouble>(reduceOp, comm);
   129→        default:
   130→          C10_THROW_ERROR(
   131→              TypeError,
   132→              "PreMulSum Data type must be half, float, bfloat16 or double");
   133→          return ncclRedOp_t{};
   134→      }
   135→#else
   136→      C10_THROW_ERROR(ValueError, "PreMulSum requires NCCL>=2.11.1");
   137→#endif // ENABLE_NCCL_PREMUL_SUM_SUPPORT
   138→    }
   139→    return ncclOp.at(reduceOp);
   140→  } catch (const std::out_of_range&) {
   141→    switch (reduceOp) {
   142→      case ReduceOp::AVG:
   143→        C10_THROW_ERROR(
   144→            ValueError,
   145→            c10::str(
   146→                "AVG requires NCCL 2.10+. The current version is ",
   147→                NCCL_MAJOR,
   148→                ".",
   149→                NCCL_MINOR));
   150→        break;
   151→      case ReduceOp::BAND:
   152→        C10_THROW_ERROR(ValueError, "Cannot use ReduceOp.BAND with NCCL");
   153→        break;
   154→      case ReduceOp::BOR:
   155→        C10_THROW_ERROR(ValueError, "Cannot use ReduceOp.BOR with NCCL");
   156→        break;
   157→      case ReduceOp::BXOR:
   158→        C10_THROW_ERROR(ValueError, "Cannot use ReduceOp.BXOR with NCCL");
   159→        break;
   160→      default:
   161→        C10_THROW_ERROR(ValueError, "Unhandled ReduceOp");
   162→        break;
   163→    }
   164→  }
   165→}
