   223→inline void errorIfCapturingNonCapturableNCCL(c10::cuda::CaptureStatus status) {
   224→  // parentheses avoid some compiler warnings
   225→  static const uint64_t min_version =
   226→      (((uint64_t)2) << 32) + (((uint64_t)9) << 16) + ((uint64_t)6);
   227→  static const uint64_t cur_version = torch::cuda::nccl::version();
   228→  if (cur_version < min_version) {
   229→    TORCH_CHECK_WITH(
   230→        NotImplementedError,
   231→        status == c10::cuda::CaptureStatus::None,
   232→        "Capturing NCCL collectives is only allowed with NCCL >= 2.9.6");
   233→  }
