   236→// When TORCH_NCCL_USE_TENSOR_REGISTER_ALLOCATOR_HOOK is set, all tensors (no
   237→// matter how they have been allocated) are registered with all NCCL comms.
   238→bool shouldAllCommunicatorsRegisterAllTensors() {
   239→#ifdef NCCL_HAS_COMM_REGISTER
   240→  static const bool flag = [] {
   241→    const bool flag =
   242→        getCvarBool(TORCH_NCCL_USE_TENSOR_REGISTER_ALLOCATOR_HOOK, false);
   243→    if (flag &&
   244→        c10::cuda::CUDACachingAllocator::CUDAAllocatorConfig::
   245→            expandable_segments()) {
   246→      LOG(INFO)
   247→          << "disables TORCH_NCCL_USE_TENSOR_REGISTER_ALLOCATOR_HOOK because it is not compatible with CUDA allocator expandable segments mode.";
   248→      return false;
   249→    }
   250→    return flag;
   251→  }();
   252→  return flag;
   253→#else
   254→  return false;
   255→#endif // NCCL_HAS_COMM_REGISTER
   256→}
