   258→} // namespace
   259→
   260→// Map each communicator to the memory pools registered with it.
   261→// This map is used when the caching allocator allocates or frees segments, in
   262→// order to register or deregister them with the relevant NCCL communicators.
   263→// There are two modes to do so:
   264→// - If TORCH_NCCL_USE_TENSOR_REGISTER_ALLOCATOR_HOOK=1 then *ALL* segments
   265→//   will be registered with *ALL* NCCL communicators (for the same device),
   266→//   even if they were allocated with cudaMalloc (which NCCL doesn't like).
   267→// - If a MemPool is explicitly registered with a ProcessGroup, then all its
   268→//   segments (current and future) will be registered with the NCCL communicator
   269→//   corresponding to the pool's device. This works best if the MemPool is set
   270→//   up to use ncclMemAlloc (which is exposed by the ProcessGroup).
   271→// Implementation notes:
   272→// - We cannot reuse devNCCLCommMap_ in each ProcessGroup because the key may be
   273→//   ranks rather than device in point-to-point case.
   274→// - This map has also to be maintained as global variable since the register
   275→//   hooks are called outside the scope of any PG, thus we need traverse
   276→//   communicators in all PGs.
   277→
   278→// MemPoolSet has ids of mempools used with this communicator, and whether they
   279→// were registered with window APIs or not
   280→using MemPoolSet = std::unordered_set<
   281→    std::tuple<c10::cuda::MempoolId_t, bool>,
   282→    c10::hash<std::tuple<c10::cuda::MempoolId_t, bool>>>;
   283→static std::unordered_map<std::shared_ptr<NCCLComm>, MemPoolSet>
   284→    ncclCommMemPoolMap;
   285→static std::mutex ncclCommMemPoolMapMutex;
   286→
   287→std::atomic<bool> ProcessGroupNCCL::shouldDump_(false);
   288→
   289→static void cacheAllocatorRegisterHook(
   290→    const c10::cuda::CUDACachingAllocator::TraceEntry& te) {
   291→  // Register after SEGMENT_ALLOC
   292→  if (te.action_ !=
   293→      c10::cuda::CUDACachingAllocator::TraceEntry::Action::SEGMENT_ALLOC) {
   294→    return;
   295→  }
   296→
   297→  std::lock_guard<std::mutex> lock(ncclCommMemPoolMapMutex);
   298→  for (auto& [ncclComm, memPools] : ncclCommMemPoolMap) {
   299→    if (te.device_ == ncclComm->getDeviceIndex()) {
   300→      bool symm = false;
   301→      bool should_register = shouldAllCommunicatorsRegisterAllTensors();
   302→      auto it =
   303→          std::find_if(memPools.begin(), memPools.end(), [&](const auto& tup) {
   304→            return std::get<0>(tup) == te.mempool_;
   305→          });
   306→      if (it != memPools.end()) {
   307→        should_register = true;
   308→        symm = std::get<1>(*it);
   309→      }
   310→      if (should_register) {
   311→        // NOLINTNEXTLINE(performance-no-int-to-ptr)
   312→        ncclComm->registerSegment(
   313→            reinterpret_cast<void*>(te.addr_),
   314→            te.size_,
   315→            /*errorOnRereg*/ false,
   316→            /*window*/ symm);
   317→      }
   318→    }
   319→  }
   320→}
   321→
   322→static void cacheAllocatorDeregisterHook(
   323→    const c10::cuda::CUDACachingAllocator::TraceEntry& te) {
   324→  // deregister before SEGMENT_FREE
   325→  if (te.action_ !=
   326→      c10::cuda::CUDACachingAllocator::TraceEntry::Action::SEGMENT_FREE) {
   327→    return;
   328→  }
   329→
   330→  std::lock_guard<std::mutex> lock(ncclCommMemPoolMapMutex);
   331→  for (auto& [ncclComm, memPools] : ncclCommMemPoolMap) {
   332→    if (te.device_ == ncclComm->getDeviceIndex()) {
   333→      bool symm = false;
   334→      bool should_register = shouldAllCommunicatorsRegisterAllTensors();
   335→      auto it =
   336→          std::find_if(memPools.begin(), memPools.end(), [&](const auto& tup) {
   337→            return std::get<0>(tup) == te.mempool_;
   338→          });
   339→      if (it != memPools.end()) {
   340→        should_register = true;
   341→        symm = std::get<1>(*it);
   342→      }
   343→      if (should_register) {
   344→        // NOLINTNEXTLINE(performance-no-int-to-ptr)
   345→        ncclComm->deregisterSegment(reinterpret_cast<void*>(te.addr_), symm);
   346→      }
   347→    }
   348→  }
   349→}
   350→
   351→static void attachAllocatorHooks() {
   352→  static auto flag [[maybe_unused]] = [] {
   353→    // Attaching hooks fails if CUDACachingAllocator is not initialized, so
   354→    // Init for CUDA is called (and is a no-op if CUDA is already
   355→    // initialized).
   356→    at::globalContext().lazyInitDevice(c10::DeviceType::CUDA);
   357→    c10::cuda::CUDACachingAllocator::attachAllocatorTraceTracker(
   358→        &cacheAllocatorRegisterHook);
   359→    c10::cuda::CUDACachingAllocator::attachAllocatorTraceTracker(
   360→        &cacheAllocatorDeregisterHook);
   361→    return true;
   362→  }();
   363→}
