   365→static std::
   366→    unordered_map<std::string, std::unordered_map<std::string, std::string>>
   367→    getNCCLCommDumpMap() {
   368→#if (defined(IS_NCCLX) || defined(USE_ROCM)) && defined(NCCL_COMM_DUMP)
   369→  std::unordered_map<
   370→      std::string /* ncclUniqueID */,
   371→      std::unordered_map<std::string, std::string> /* dump from this comm */>
   372→      ncclDumpMap;
   373→  // dump_nccl_trace is only called from the default PG (local_id_=0), but we
   374→  // want to dump from all comms so we need to iterate over ncclCommMemPoolMap,
   375→  // which is static
   376→  std::vector<std::shared_ptr<NCCLComm>> allNCCLComms;
   377→  // within the critical section, we don't want to dump while holding the lock
   378→  // as dump might hang
   379→  {
   380→    std::lock_guard<std::mutex> lock(ncclCommMemPoolMapMutex);
   381→    for (auto& [ncclComm, _] : ncclCommMemPoolMap) {
   382→      allNCCLComms.push_back(ncclComm);
   383→    }
   384→  }
   385→  for (auto& ncclComm : allNCCLComms) {
   386→    ncclDumpMap[ncclComm->getUniqueHash()] = ncclComm->ncclCommDump();
   387→  }
   388→  return ncclDumpMap;
   389→#else
   390→  return std::unordered_map<
   391→      std::string,
   392→      std::unordered_map<std::string, std::string>>();
   393→#endif // (defined(IS_NCCLX) || defined(USE_ROCM)) && defined(NCCL_COMM_DUMP)
   394→}
