   428→gil_checker_t& get_gil_checker() {
   429→  static gil_checker_t gil_checker = nullptr;
   430→  return gil_checker;
   431→}
   432→
   433→static std::future<bool> launchAsyncGilCheck() {
   434→  std::promise<bool> resultPromise;
   435→  std::future<bool> resultFuture = resultPromise.get_future();
   436→  TORCH_CHECK(get_gil_checker(), "Can't check GIL with null GIL checker");
   437→  std::thread workerThread([promise = std::move(resultPromise)]() mutable {
   438→    c10::setThreadName("pt_nccl_gil_chk");
   439→
   440→    try {
   441→      auto& gil_checker = get_gil_checker();
   442→      promise.set_value((*gil_checker)());
   443→    } catch (...) {
   444→      promise.set_exception(std::current_exception());
   445→    }
   446→  });
   447→
   448→  // Detach the thread to allow it to run independently
   449→  workerThread.detach();
   450→
   451→  return resultFuture;
   452→}
