   508→ProcessGroupNCCL::WorkNCCL::WorkNCCL(
   509→    std::string pgUID,
   510→    std::string pgDesc,
   511→    at::Device& device,
   512→    int rank,
   513→    OpType opType,
   514→    uint64_t seq,
   515→    bool isP2P,
   516→    const char* profilingTitle,
   517→    const std::optional<std::vector<at::Tensor>>& inputs,
   518→    bool enableTiming,
   519→    bool cudaEventCacheEnabled,
   520→    DebugLevel distDebugLevel)
   521→    : Work(rank, opType, profilingTitle, inputs),
   522→      pgUID_(std::move(pgUID)),
   523→      pgDesc_(std::move(pgDesc)),
   524→      device_(device),
   525→      workStartTime_(std::chrono::steady_clock::now()),
   526→      seq_(seq),
   527→      isP2P_(isP2P),
   528→      timingEnabled_(enableTiming),
   529→      distDebugLevel_(distDebugLevel) {
   530→  // Creates the CUDA event wrappers
   531→  // Note: The actual events are lazily created when first recorded to with
   532→  // DEFAULT_FLAGS = cudaEventDisableTiming.
   533→  if (cudaEventCacheEnabled) {
   534→    ncclStartEvent_ = enableTiming
   535→        ? CUDAEventCache::get(device.index())->create(enableTiming)
   536→        : nullptr;
   537→    ncclEndEvent_ = CUDAEventCache::get(device.index())->create(enableTiming);
   538→  } else {
   539→    ncclStartEvent_ = enableTiming
   540→        ? std::make_shared<at::cuda::CUDAEvent>(cudaEventDefault)
   541→        : nullptr;
   542→    ncclEndEvent_ = std::make_shared<at::cuda::CUDAEvent>(
   543→        enableTiming ? cudaEventDefault : cudaEventDisableTiming);
   544→  }
   545→  futureWorkResult_ =
   546→      c10::make_intrusive<at::ivalue::Future>(c10::AnyEnumType::get());
   547→  // other functions expect an initialized ptr
   548→  stashed_for_allocator_safety_ = std::make_shared<TensorShelf>();
   549→}
