   601→void ProcessGroupNCCL::WorkNCCL::checkAndSetException() {
   602→  if (exception()) {
   603→    // We already have an exception.
   604→    return;
   605→  }
   606→
   607→  auto exception_ptr = checkForNCCLErrors();
   608→  std::unique_lock<std::mutex> lock(mutex_);
   609→  exception_ = exception_ptr;
   610→  if (exception_) {
   611→    LOG(ERROR) << logPrefix() << "Collective " << *this
   612→               << " raised the following async exception: "
   613→               << getExceptionMsgFromExceptionPtr(exception_);
   614→
   615→    // Mark future result as ERROR
   616→    if (futureWorkResult_ && !futureWorkResult_->completed()) {
   617→      futureWorkResult_->markCompleted(
   618→          at::IValue(static_cast<uint8_t>(WorkResult::COMM_ERROR)));
   619→    }
   620→  }
   621→}
