   640→bool ProcessGroupNCCL::WorkNCCL::startedGPUExecutionInternal() const {
   641→  // if timing is disabled we won't have allocated start events
   642→  if (!timingEnabled_) {
   643→    return false;
   644→  }
   645→  // Checking the work's corresponding CUDA event's status
   646→  if (!ncclStartEvent_->query()) {
   647→    return false;
   648→  }
   649→  return true;
