   651→
   652→bool ProcessGroupNCCL::WorkNCCL::finishedGPUExecutionInternal() const {
   653→  // Checking the work's corresponding CUDA event's status
   654→  // It calls `cudaEventQuery` eventually. Although this seems to be a
   655→  // non-blocking call, but we did notice hangs in the past. It can
   656→  // hang if another thread is holding the CUDA global context lock. For
   657→  // example, when doing a `cudaDeviceSynchronize` or even
   658→  // `cudaStreamSynchronize`.
   659→  if (!ncclEndEvent_->query()) {
   660→    return false;
   661→  }
   662→  return true;
   663→}
   664→
   665→bool ProcessGroupNCCL::WorkNCCL::checkTimeout(
   666→    std::optional<std::chrono::milliseconds> timeout) {
   667→  STATIC_SCOPED_WAIT_COUNTER(
   668→      pytorch.wait_counter.ProcessGroupNCCL__checkTimeout);
   669→  auto currentTimepoint = std::chrono::steady_clock::now();
   670→  auto timeElapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
   671→      currentTimepoint - workStartTime_);
   672→  auto workTimeout = timeout ? *timeout : opTimeout_;
   673→
   674→  if (timeElapsed < workTimeout) {
   675→    return false;
   676→  }
   677→
   678→  // Timed out
   679→
   680→  std::string exceptionMsg = c10::str(
   681→      logPrefix(),
   682→      "Watchdog caught collective operation timeout: ",
   683→      *this,
   684→      " ran for ",
   685→      timeElapsed.count(),
   686→      " milliseconds before timing out.");
   687→
   688→  LOG(ERROR) << exceptionMsg;
   689→
   690→  std::exception_ptr exception_ptr =
   691→      std::make_exception_ptr(C10_BUILD_ERROR(DistBackendError, exceptionMsg));
   692→  if (!exception()) {
   693→    // if there is already an error, we don't override it
   694→    setException(exception_ptr);
   695→  }
   696→
   697→  // Mark future result as TIMEOUT
   698→  if (futureWorkResult_ && !futureWorkResult_->completed()) {
   699→    futureWorkResult_->markCompleted(
   700→        at::IValue(static_cast<uint8_t>(WorkResult::TIMEOUT)));
   701→  }
   702→  return true;
   703→}
   704→
   705→// Print the traceback of the collective at call time
   706→std::string ProcessGroupNCCL::WorkNCCL::getTraceback() const {
   707→  // First step we get the corresponding record entry from FR, based on work's
   708→  // trace_id_ and trace_reset_epoch_
   709→  std::optional<FlightRecorderCUDA::Entry> entry =
   710→      FlightRecorderCUDA::get()->getEntry(trace_id_, trace_reset_epoch_);
   711→  if (entry.has_value()) {
   712→    auto entryVal = entry.value();
   713→    // Get stack trace from FR entry, in string format
   714→    // Note: `getTraceback` call below invokes `torch::symbolize`, which may
   715→    // need to acquire the GIL. In order for watchdog to be block-free, we make
   716→    // the call with std::async.
   717→    auto future = std::async(
   718→        std::launch::async, [&entryVal]() { return entryVal.getTraceback(); });
   719→    // Wait for the future to complete or timeout
   720→    auto status = future.wait_for(std::chrono::seconds(8));
   721→    if (status == std::future_status::ready) {
   722→      return future.get();
   723→    }
   724→  }
   725→  return "";
   726→}
   727→
   728→// Print the traceback of the collective at call time
   729→void ProcessGroupNCCL::WorkNCCL::printTraceback() const {
   730→  std::string tracebackStr = getTraceback();
   731→  if (!tracebackStr.empty()) {
   732→    LOG(ERROR) << "Stack trace of the failed collective: \n" << tracebackStr;
   733→  } // else, symbolizer probably timed out, we skip logging the stack trace.
   734→  else {
   735→    LOG(ERROR)
   736→        << "Stack trace of the failed collective not found, "
   737→        << "potentially because FlightRecorder is disabled. "
   738→        << "You can enable it by setting TORCH_NCCL_TRACE_BUFFER_SIZE to a non-zero value.";
   739→  }
   740→}
   741→
   742→void ProcessGroupNCCL::WorkNCCL::handleException(
   743→    ErrorHandlingMode errorHandling) {
   744→  if (exception_) {
   745→    auto exceptionMsg = c10::str(
   746→        "Some NCCL operations have failed or timed out. Due to the ",
   747→        "asynchronous nature of CUDA kernels, subsequent GPU operations ",
   748→        "might run on corrupted/incomplete data.");
   749→    LOG(ERROR) << logPrefix() << exceptionMsg;
   750→    C10_LOG_API_USAGE_ONCE("ProcessGroupNCCL.WorkNCCL.handleException");
   751→
   752→    auto logger = c10d::C10dLogger::getLogger();
   753→    if (logger) {
   754→      ::c10d::C10dLoggingData data;
   755→      data.strings["work_nccl_exception"] =
   756→          getExceptionMsgFromExceptionPtr(exception_);
   757→      logger->log(data);
   758→    }
   759→
   760→    if (SHOULD_TEAR_DOWN(errorHandling)) {
   761→      auto tearDownMsg = c10::str(
   762→          "To avoid data inconsistency, we are taking the entire process down.");
   763→      LOG(ERROR) << logPrefix() << tearDownMsg;
   764→      std::rethrow_exception(exception_);
   765→    }
   766→  }
   767→}
   768→
   769→void ProcessGroupNCCL::WorkNCCL::synchronize() {
   770→  synchronizeStream();
   771→  if (c10d::allow_inflight_collective_as_graph_input()) {
