610: std::string getNcclVersion() {
611:   static std::string versionString = []() {
612:     auto [ncclMajor, ncclMinor, ncclPatch] = getNcclVersionTuple();
613:     std::string versionString;
614:     if (ncclMajor == 0 && ncclMinor == 0 && ncclPatch == 0) {
615:       versionString = "Unknown NCCL version";
616:     } else {
617:       versionString = std::to_string(ncclMajor) + "." +
618:           std::to_string(ncclMinor) + "." + std::to_string(ncclPatch);
619: #ifdef NCCL_SUFFIX
620:       const auto ncclSuffix = std::string(NCCL_SUFFIX);
621:       if (!ncclSuffix.empty()) {
622:         versionString += "." + ncclSuffix;
623:       }
624: #endif
625:     }
626:     return versionString;
627:   }();
628: 
629:   return versionString;
630: }
631: 
632: std::tuple<int, int, int> getNcclVersionTuple() {
633:   static std::tuple<int, int, int> versionTuple = []() {
634:     int version = getNcclVersionNumber();
635:     // can't compute the version if call did not return successfully or version
636:     // code < 100 (corresponding to 0.1.0)
637:     if (version < 100) {
638:       return std::make_tuple(0, 0, 0);
639:     }
640:     // NCCL changed version coding starting 2.9
641:     const int majorBase = version < 2900 ? 1000 : 10000;
642:     const int minorBase = 100;
643:     auto ncclMajor = version / majorBase;
644:     auto ncclMinor = (version % majorBase) / minorBase;
645:     auto ncclPatch = version % minorBase;
646:     return std::make_tuple(ncclMajor, ncclMinor, ncclPatch);
647:   }();
648:   return versionTuple;
649: }
