651: int getNcclVersionNumber() {
652:   static int version = []() {
653:     int version = 0;
654:     ncclResult_t status = ncclGetVersion(&version);
655:     if (status != ncclSuccess) {
656:       return 0; // Error.
657:     }
658:     return version;
659:   }();
660:   return version;
661: }
