663: size_t hashTensors(const std::vector<at::Tensor>& tensors) {
664:   size_t hash = 0;
665:   for (auto& tensor : tensors) {
666:     if (tensor.numel() > 0 && tensor.storage()) {
667:       size_t data_size = tensor.storage().nbytes();
668:       if (data_size > 0 && tensor.storage().data_ptr()) {
669:         auto src = static_cast<const char*>(tensor.storage().data_ptr().get());
670:         std::vector<char> dst(data_size);
671:         // This is needed so that we trigger a device synchronization so we can
672:         // get the collective finished if launched on GPU and hash its output.
673:         AT_CUDA_CHECK(
674:             cudaMemcpy(dst.data(), src, data_size, cudaMemcpyDeviceToHost));
675:         for (size_t i = 0; i < data_size; ++i) {
676:           // Update the hash for each byte in the tensor
677:           hash = c10::hash_combine(hash, c10::get_hash(dst[i], data_size));
678:         }
679:       }
680:     }
681:   }
682:   return hash;
683: }
