685: // Default value: 30 minutes
686: int nccl_nonblocking_timeout() {
687:   static int timeout = -2; // -2 means not initialized
688:   if (timeout == -2) {
689:     const auto val = c10::utils::get_env("TORCH_NCCL_NONBLOCKING_TIMEOUT");
690:     if (val.has_value() && !val.value().empty()) {
691:       timeout = stoi(val.value());
692:     } else {
693:       // Default value consistent with kBackendDefaultTimeout
694:       timeout = 30 * 60;
695:     }
696:   }
697:   return timeout;
698: }
