705: // Provides additional detail into NCCL error codes based on when these are
706: // thrown in the NCCL codebase.
707: std::string getNcclErrorDetailStr(
708:     ncclResult_t error,
709:     std::optional<std::string> processGroupFailureReason /* = std::nullopt */
710: ) {
711:   // Prioritize failure reason provided by PG NCCL first, as it can abort
712:   // communicators when it encounters collective timeouts, etc.
713:   if (processGroupFailureReason != std::nullopt) {
714:     return *processGroupFailureReason;
715:   }
716:   std::string interpret;
717:   std::string err;
718: #ifdef ENABLE_NCCL_GET_LAST_ERROR
719:   auto ret = ncclGetLastError(nullptr);
720:   if (ret) {
721:     err = "\nLast error:\n" + std::string(ret);
722:   } else {
723:     err = "\nLast error: Unknown NCCL Error\n";
724:   }
725: #endif
726:   switch (error) {
727:     case ncclUnhandledCudaError:
728:       interpret = "ncclUnhandledCudaError: Call to CUDA function failed.";
729:       break;
730:     case ncclSystemError:
731:       interpret =
732:           "ncclSystemError: System call (e.g. socket, malloc) or external library call failed or device error. ";
733: #ifndef NCCL_REMOTE_ERROR
734:       // Before ncclRemoteError was created, unexpected remote disconnect was
735:       // categorized as ncclSystemError
736:       interpret += "It can be also caused by unexpected exit of a remote peer.";
737: #endif
738:       break;
739:     case ncclInternalError:
740:       interpret = "ncclInternalError: Internal check failed.";
741:       break;
742:     case ncclInvalidArgument:
743:       interpret = "ncclInvalidArgument: Invalid value for an argument.";
744:       break;
745:     case ncclInvalidUsage:
746:       interpret =
747:           "ncclInvalidUsage: This usually reflects invalid usage of NCCL library.";
748:       break;
749: #ifdef NCCL_REMOTE_ERROR
750:     case ncclRemoteError:
751:       interpret =
752:           "ncclRemoteError: A call failed possibly due to a network error or a remote process exiting prematurely.";
753:       break;
754: #endif
755:     default:
756:       interpret = "Unknown NCCL error!";
757:   }
758:   return interpret + err;
759: }
